INSERT INTO `pytania` VALUES (1,'Podczas rutynowej kontroli technik odkryl, ze oprogramowanie zainstalowane na komputerze potajemnie zbieralo dane o stronach internetowych, ktore byly odwiedzane przez uzytkownikow komputera. Jaki rodzaj zagrozenia wplywa na ten komputer?','false',0),(2,'Ktory termin odnosi sie do sieci, ktora zapewnia bezpieczny dostep do biur korporacyjnych przez dostawcow, klientow i wspolpracownikow?','false',0),(3,'Duza korporacja zmodyfikowala swoja siec, aby umozliwic uzytkownikom dostep do zasobow sieciowych z ich osobistych laptopow i smartfonow. Ktory trend sieciowy to opisuje?','false',0),(4,'Co to jest dostawca uslug internetowych (ISP)?','false',0),(6,'Pracownik oddzialu tworzy wycene dla klienta. Aby to zrobic, pracownik musi uzyskac dostep do poufnych informacji o cenach z wewnetrznych serwerow w Centrali. Do jakiego rodzaju sieci mialby dostep pracownik?','false',0),(7,'Ktore stwierdzenie opisuje wykorzystanie technologii sieci powerline?','false',0),(8,'Technik sieciowy pracuje nad siecia bezprzewodowa w klinice medycznej. Technik przypadkowo ustawia siec bezprzewodowa, aby pacjenci mogli zobaczyc dane dokumentacji medycznej innych pacjentow. Ktora z czterech cech sieci zostala naruszona w tej sytuacji?','false',0),(10,'Jakie dwa kryteria sa stosowane, aby pomoc w wyborze nosnika sieciowego sposrod roznych mediow sieciowych? (Wybierz dwa.)','false',1),(11,'Jaki rodzaj ruchu sieciowego wymaga QoS?','false',0),(12,'Uzytkownik wdraza zabezpieczenia w malej sieci biurowej. Ktore dwie czynnosci zapewnilyby minimalne wymagania bezpieczenstwa dla tej sieci? (Wybierz dwa.)','false',1),(13,'Hasla moga byc uzywane do ograniczenia dostepu do calosci lub czesci Cisco IOS. Wybierz tryby i interfejsy, ktore mozna chronic haslami. (Wybierz trzy.)','false',1),(14,'Ktory interfejs umozliwia zdalne zarzadzanie przelacznikiem warstwy 2?','false',0),(15,'Jaka funkcje ma nacisniecie klawisza Tab podczas wprowadzania polecenia w IOS?','false',0),(16,'Probujac rozwiazac problem z siecia, technik wprowadzil wiele zmian w biezacym pliku konfiguracyjnym routera. Zmiany nie rozwiazaly problemu i nie zostaly zapisane. Jakie dzialania moze podjac technik, aby odrzucic zmiany i pracowac z plikiem w pamieci NVRAM?','false',0),(17,'Administrator uzywa kombinacji klawiszy Ctrl-Shift-6 na przelaczniku po wydaniu polecenia ping. Jaki jest cel uzywania tych nacisniec klawiszy?','false',0),(18,'Zapoznaj sie z eksponatem. Administrator sieci konfiguruje kontrole dostepu, aby przelaczyc SW1. Jesli administrator uzywa polaczenia konsoli do polaczenia z przelacznikiem, jakie haslo jest potrzebne, aby uzyskac dostep do trybu EXEC uzytkownika?','z18.jpg',0),(19,'Technik konfiguruje przelacznik za pomoca nastepujacych polecen: (zobacz obrazek). Co konfiguruje technik?','z19.jpg',0),(20,'Ktore polecenie lub kombinacja klawiszy pozwala uzytkownikowi powrocic do poprzedniego poziomu w hierarchii polecen?','false',0),(21,'Jakie sa dwie cechy pamieci RAM w urzadzeniu Cisco? (Wybierz dwa.)','false',1),(22,'Ktore dwie nazwy hostow sa zgodne z wytycznymi dotyczacymi konwencji nazewnictwa na urzadzeniach Cisco IOS? (Wybierz dwa.)','false',1),(23,'Czym rozni sie SSH od Telnet?','false',0),(25,'Jakie sa trzy cechy SVI? (Wybierz trzy.)','false',1),(26,'Jakie polecenie sluzy do weryfikacji stanu interfejsow przelacznikow, w tym statusu interfejsow i skonfigurowanego adresu IP?','false',0),(29,'W poleceniu show running-config, ktora czesc skladni jest reprezentowana przez running-config?','false',0),(30,'Po wprowadzeniu zmian w konfiguracji na przelaczniku Cisco administrator sieci wydaje polecenie copy running-config startup-config. Jaki jest wynik wydania tego polecenia?','false',0),(31,'Jakie polecenie zapobiegnie wyswietlaniu wszystkich niezaszyfrowanych hasel w postaci zwyklego tekstu w pliku konfiguracyjnym?','false',0),(32,'Administrator sieci wprowadza polecenie szyfrowania hasla uslugi w trybie konfiguracji routera. Co osiaga to polecenie?','false',0),(33,'Jaka metode moga uzyc dwa komputery, aby upewnic sie, ze pakiety nie zostana upuszczone, poniewaz zbyt wiele danych jest wysylanych zbyt szybko?',NULL,0),(34,'Ktore stwierdzenie dokladnie opisuje proces enkapsulacji TCP/IP, gdy komputer wysyla dane do sieci?','false',0),(35,'Jakie trzy protokoly warstwy aplikacji sa czescia pakietu protokolow TCP/IP? (Wybierz trzy.)','false',1),(37,'Ktora nazwa jest przypisana do PDU warstwy transportowej?','false',0),(38,'Gdy adresowanie IPv4 jest konfigurowane recznie na serwerze internetowym, ktora wlasciwosc konfiguracji IPv4 identyfikuje czesc sieci i hosta dla adresu IPv4?','false',0),(39,'Jaki proces wiaze sie z umieszczeniem jednego PDU wewnatrz innego PDU?','false',0),(40,'Ktora warstwa jest odpowiedzialna za kierowanie wiadomosci przez siec internetowa w modelu TCP/IP?','false',0),(42,'Ktory format PDU jest uzywany, gdy bity sa odbierane z nosnika sieciowego przez karte sieciowa hosta?','false',0),(43,'Zapoznaj sie z eksponatem. ServerB probuje skontaktowac sie z HostA. Ktore dwa stwierdzenia poprawnie identyfikuja adresowanie, ktore ServerB wygeneruje w tym procesie? (Wybierz dwa.)','z43.jpg',1),(44,'Ktora metoda pozwala komputerowi odpowiednio reagowac, gdy zada danych z serwera, a odpowiedz serwera zajmuje zbyt duzo czasu?',NULL,0),(45,'Klient internetowy otrzymuje odpowiedz dla strony internetowej z serwera WWW. Z perspektywy klienta, jaka jest poprawna kolejnosc stosu protokolow, ktory jest uzywany do dekodowania otrzymanej transmisji?',NULL,0),(46,'Ktore dwie warstwy modelu OSI maja taka sama funkcjonalnosc jak pojedyncza warstwa modelu TCP/IP? (Wybierz dwa.)',NULL,1),(47,'Na ktorej warstwie modelu OSI zostalby dodany adres logiczny podczas enkapsulacji?',NULL,0),(48,'Jaka jest cecha wiadomosci multiemisji?',NULL,0),(49,'Ktore stwierdzenie dotyczace protokolow sieciowych jest poprawne?',NULL,0),(50,'Jaka jest zaleta urzadzen sieciowych korzystajacych z otwartych standardowych protokolow?',NULL,0),(51,'Ktore urzadzenie pelni funkcje okreslania sciezki, ktora wiadomosci powinny przejsc przez internetworks?',NULL,0),(52,'Otworz cwiczenie PT. Wykonaj zadania w instrukcjach cwiczenia, a nastepnie odpowiedz na pytanie. Jaki jest adres IP wirtualnego interfejsu przelacznika (SVI) na Switch0?','z52.jpg',0),(53,'Dlaczego przelacznik warstwy 2 mialby potrzebowac adresu IP?',NULL,0),(54,'Zapoznaj sie z eksponatem. Administrator probuje skonfigurowac przelacznik, ale otrzymuje komunikat o bledzie wyswietlany na eksponacie. Jaki jest problem?','z54.jpg',0),(55,'Jaki termin opisuje siec nalezaca do jednej organizacji, ktora zapewnia bezpieczny dostep osobom, ktore pracuja dla innej organizacji?',NULL,0),(56,'Jaki termin opisuje przechowywanie plikow osobistych na serwerach przez Internet, aby zapewnic dostep w dowolnym miejscu, w dowolnym czasie i na dowolnym urzadzeniu?',NULL,0),(57,'Jaki termin opisuje siec, w ktorej jeden komputer moze byc zarowno klientem, jak i serwerem?',NULL,0),(58,'Jaki termin opisuje rodzaj sieci uzywanej przez osoby, ktore pracuja z domu lub z malego zdalnego biura?',NULL,0),(59,'Jaki termin opisuje model obliczeniowy, w ktorym oprogramowanie serwerowe dziala na dedykowanych komputerach?',NULL,0),(61,'Jaki termin opisuje technologie, ktora umozliwia urzadzeniom laczenie sie z siecia LAN za pomoca gniazdka elektrycznego?',NULL,0),(62,'Jaki termin opisuje polityke, ktora pozwala urzadzeniom sieciowym zarzadzac przeplywem danych, aby nadac pierwszenstwo glosowi i wideo?',NULL,0),(63,'Jaki termin opisuje prywatna kolekcje sieci LAN i WAN, ktora nalezy do organizacji?',NULL,0),(64,'Jaki termin opisuje mozliwosc korzystania z urzadzen osobistych w sieci biznesowej lub kampusowej?',NULL,0),(65,'Na ktorej warstwie OSI jest zrodlowy adres IP dodawany do PDU podczas procesu enkapsulacji?',NULL,0),(66,'W ktorej warstwie OSI numer portu docelowego jest dodawany do PDU podczas procesu enkapsulacji?',NULL,0),(67,'W ktorej warstwie OSI dane sa dodawane do PDU podczas procesu enkapsulacji?',NULL,0),(68,'Na ktorej warstwie OSI jest zrodlowy adres IP dodawany do PDU podczas procesu enkapsulacji?',NULL,0),(69,'Ktora z ponizszych jest nazwa wszystkich komputerow podlaczonych do sieci, ktore uczestnicza bezposrednio w komunikacji sieciowej?',NULL,0),(70,'Na ktorej warstwie OSI jest docelowy adres IP dodawany do PDU podczas procesu enkapsulacji?',NULL,0),(71,'W ktorej warstwie OSI jest zrodlowy adres MAC dodawany do PDU podczas procesu enkapsulacji?',NULL,0),(72,'W ktorej warstwie OSI numer portu zrodlowego jest dodawany do PDU podczas procesu enkapsulacji?',NULL,0),(73,'Na ktorej warstwie OSI jest docelowy adres MAC dodawany do PDU podczas procesu enkapsulacji?',NULL,0),(74,'Kiedy dane sa kodowane jako impulsy swiatla, jakie nosniki sa uzywane do transmisji danych?',NULL,0),(75,'Ktore dwa urzadzenia sa urzadzeniami posredniczacymi? (Wybierz dwa)',NULL,1),(76,'Uczelnia buduje nowy akademik na swoim kampusie. Pracownicy kopia w ziemi, aby zainstalowac nowa rure wodna do akademika. Pracownik przypadkowo uszkadza kabel swiatlowodowy, ktory laczy dwa istniejace akademiki z centrum danych kampusu. Chociaz kabel zostal odciety, studenci w akademikach doswiadczaja tylko bardzo krotkiej przerwy w uslugach sieciowych. Jaka charakterystyka sieci jest tutaj pokazana?',NULL,0);
