INSERT INTO `pytania2` VALUES (1,'Jaki jest cel warstwy fizycznej OSI?',NULL,0),(2,'Dlaczego uzywa sie dwoch wlokien dla jednego polaczenia optycznego?',NULL,0),(3,'Jaka cecha opisuje crosstalk?',NULL,0),(4,'Jaka procedura jest uzywana do zmniejszenia efektu crosstalk w kablach miedzianych?',NULL,0),(6,'Administrator sieci mierzy transfer bitow wzdluz podstawy firmy dla misji krytyczna aplikacja finansowa. Administrator zauwaza ze przepustowosc sieci wydaje sie nizsza niz oczekiwana przepustowosc. Jakie trzy czynniki moglyby wplyw na roznice w przepustowosci? (Wybierz trzy.)',NULL,1),(7,'Jakie sa dwie cechy kabla swiatlowodowego? (Wybierz dwa.)',NULL,1),(8,'Jaka jest podstawowa rola warstwy fizycznej w transmisja danych w sieci?',NULL,0),(9,'Z uzyciem nieekranowanej pary skreconej miedzi W sieci, co powoduje przesluch w kablu? pary?',NULL,0),(10,'Odnies sie do grafiki. Jaki rodzaj okablowania jest pokazany?','./img/z10.jpg',0),(11,'Oprocz dlugosci kabla, jakie dwa czynniki moglyby zaklocic komunikacje przeprowadzona przez Kable UTP? (Wybierz dwa.)',NULL,1),(12,'Odniesienie do grafiki. Jaki typ okablowania jest pokazany?','./img/z12.jpg',0),(13,'Ktore dwa urzadzenia najczesciej wplywaja na lacznosc bezprzewodowa sieci? (Wybierz dwa.)',NULL,1),(14,'Ktore dwa stwierdzenia opisuja uslugi zapewnia warstwa lacza danych? (Wybierz dwie.)',NULL,1),(15,'Jaka jest funkcja wartosci CRC, ktora sie znajduje w polu FCS ramki?',NULL,0),(16,'Co zawiera przyczepa ramki zwiazku danych?',NULL,0),(17,'Ktore stwierdzenie opisuje ceche pola naglowka ramki warstwy lacza danych?',NULL,0),(18,'Zespol sieciowy porownuje fizyczne WAN topologie laczenia zdalnych lokalizacji z budynek glownej siedziby. Ktora topologia zapewnia wysoka dostepnosc i laczy niektore, ale nie wszystkie, zdalne strony?',NULL,0),(19,'Jakie dwa pola lub cechy bada Ethernet aby okreslic, czy odebrany ramka jest przekazywana do danych warstwa lacza lub odrzucona przez NIC? (Wybierz dwa.)',NULL,1),(20,'Ktory rodzaj komunikacji medialnej nie wymaga arbitraz mediow w warstwie lacza danych?',NULL,0),(21,'Ktore stwierdzenie opisuje rozszerzona gwiazde topologia?',NULL,0),(22,'Jaka jest cecha podwarstwy LLC?',NULL,0),(23,'Jakie sa trzy sposoby, w jakie kontrola dostepu do mediow jest uzywane w sieciach? (Wybierz trzy.)',NULL,1),(24,'Podczas procesu kapsulkowania, co sie dzieje w warstwie lacza danych dla komputera PC podlaczonego do Ethernetu siec?',NULL,0),(25,'Jakie trzy przedmioty sa zawarte w Ethernet? naglowek i przyczepa? (Wybierz trzy.)',NULL,1),(26,'Jaki typ zasady komunikacji bylby najlepszy opisz CSMA/CD?',NULL,0),(27,'Jakie trzy podstawowe czesci sa wspolne dla wszystkich ram? rodzaje wspierane przez warstwe lacza danych? (Wybierz trzy.)',NULL,1),(28,'Ktore stwierdzenie jest prawdziwe w odniesieniu do dostepu CSMA/CD? metoda stosowana w Ethernet?',NULL,0),(29,'Czym jest funkcja auto-MDIX na przelaczniku?',NULL,0),(30,'Odnies sie do wystawy. Jaki jest docelowy MAC adres ramki Ethernet, gdy opuszcza siec serwer jesli ostatecznym celem jest PC1?','./img/z30.jpg',0),(31,'Przelacznik warstwy 2 jest uzywany do przelaczania przychodzacych ramek z portu 1000BASE-T do portu podlaczonego do Siec 100Base-T. Jaka metoda buforowania pamieci co najlepiej dzialaloby w tym zadaniu?',NULL,0),(32,'Jakie sa dwa przyklady przelaczania bezposredniego? metoda? (Wybierz dwie.)',NULL,1),(33,'Ktora metoda przesylania ramek odbiera calosc ramka i wykonuje sprawdzenie CRC w celu wykrycia bledow zanim przekazany zostanie ramka?',NULL,0),(34,'Jaki jest cel pola FCS w ramce?',NULL,0),(35,'Ktora metoda przelaczania ma najnizszy poziom opoznienie?',NULL,0),(36,'Administrator sieci laczy dwa nowoczesne przelaczniki uzywajace kabla prostego. Przelaczniki sa nowe i nigdy nie byly konfigurowane. Ktore trzy stwierdzenia sa poprawne dotyczace koncowego wyniku polaczenie? (Wybierz trzy.)',NULL,1),(37,'Jaka przewage ma system przechowywania i przekazywania metoda przelaczania zostala porownana z metoda bezposredniego przekazywania metoda przelaczania?',NULL,0),(38,'Kiedy metoda przelaczania store-and-forward jest w uzyciu, ktora czesc ramki Ethernet jest uzywana do przeprowadzic kontrole bledow?',NULL,0),(39,'Ktora metoda przelaczania wykorzystuje wartosc CRC w ramka?',NULL,0),(40,'Jakie sa dwa dzialania wykonywane przez przelacznik Cisco? (Wybierz dwa.)',NULL,1),(41,'Ktore dwa stwierdzenia opisuja cechy lub funkcje podwarstwy kontrolnej lacza logicznego w Ethernet standardy? (Wybierz dwa.)',NULL,1),(42,'Czym jest funkcja auto-MDIX?',NULL,0),(43,'Jaka przewage ma zastosowanie przekroju? metoda przelaczania zamiast magazynowania i przekazywania metoda przelaczania?',NULL,0),(44,'Ktory z nich jest adresem MAC multicast?',NULL,0),(45,'Odnies sie do wykresu. Co jest nie tak z wyswietlone zakonczenie?','./img/z45.jpg',0),(46,'Odnies sie do eksponatu. Komputer PC jest podlaczony do port konsolowy przelacznika. Wszystkie inne polaczenia sa realizowane przez lacza FastEthernet. Jakie typy Czy kable UTP moga byc uzywane do laczenia urzadzen?','./img/z46.jpg',0),(47,'Otworz aktywnosc PT. Wykonaj zadania w instrukcje dotyczace aktywnosci, a nastepnie odpowiedz na pytanie. Z ktorego portu Switch0 wysyla ramki do host z adresem IPv4 10.1.1.5?','./img/z47.jpg',0),(48,'Co oznacza termin \"oslabienie\" w danych komunikacja?',NULL,0),(49,'Co sprawia, ze wlokno jest bardziej preferowane od kabli miedzianych dla polaczone budynki? (Wybierz trzy.)',NULL,1),(50,'Jaki termin warstwy fizycznej OSI opisuje ten proces w jaki sposob jedna fala modyfikuje inna fale?',NULL,0),(51,'Jaki termin warstwy fizycznej OSI opisuje pojemnosc jakie medium moze przenosic dane?',NULL,0),(52,'Jaki termin warstwy fizycznej OSI opisuje pojemnosc na ktorym medium mozna przenosic dane?',NULL,0),(53,'Jaki termin warstwy fizycznej OSI opisuje pomiar przesy?ania bitow przez medium w okreslonym czasie okres czasu?',NULL,0),(54,'Jaki termin warstwy fizycznej OSI opisuje ilosc czasu, w tym opoznien, na przesylanie danych z jednego wskazac na inny?',NULL,0),(55,'Jaki termin zwiazany z warstwa fizyczna OSI opisuje ilosc czasu, w tym opoznien, na przemieszczenie sie danych z jednego wskazac na inny?',NULL,0),(56,'Jaki termin warstwy fizycznej OSI opisuje miare uzytecznych danych przesy?anych w okreslonym czasie?',NULL,0),(57,'Jaki termin warstwy fizycznej OSI opisuje fizyczna medium, ktory wykorzystuje impulsy elektryczne?','./img/z57.jpg',0),(58,'Jaki termin warstwy fizycznej OSI opisuje fizyczna medium, ktore wykorzystuje propagacje swiatla?','./img/z58.jpg',0),(59,'Jaki termin warstwy fizycznej OSI opisuje fizyczny medium do transmisji mikrofalowej?','./img/z59.jpg',0),(60,'Ktore dwie funkcje sa wykonywane na MAC warstwa podrzedna warstwy lacza danych OSI? (Wybierz trzy.)','./img/z60.jpg',1),(61,'Jakie dwie funkcje sa realizowane w LLC warstwa podpoziomu warstwy lacza danych OSI? (Wybierz dwa.)','./img/z61.jpg',1),(64,'Jakie dwie funkcje sa wykonywane w LLC podwarstwa warstwy lacza danych OSI? (Wybierz dwa.)','./img/z64.jpg',1),(66,'Jakie dwie funkcje sa wykonywane w LLC podwarstwa warstwy lacza danych OSI? (Wybierz dwie.)','./img/z66.jpg',1),(68,'Jakie dwie funkcje sa wykonywane w LLC podwarstwa warstwy lacza danych OSI? (Wybierz dwie.)','./img/z68.jpg',1),(70,'Jaka akcja zostanie podjeta, jesli przelacznik otrzyma ramke i ma adres MAC zrodlowy w MAC stol?','./img/z70.jpg',0),(71,'Jaka akcje podejmie przelacznik, gdy otrzyma ramke z docelowym adresem MAC FF:FF:FF:FF:FF:FF?','./img/z71.jpg',0),(72,'Jakie dzialanie nastapi, jesli host otrzyma ramke z adresem MAC docelowym, ktorego nie rozpoznaje?','./img/z72.jpg',0),(73,'Jakie dzialanie nastapi, jesli przelacznik otrzyma ramke z adresem MAC docelowym 01:00:5E:00:00:D9?','./img/z73.jpg',0),(74,'Jakie dzialanie nastapi, jesli host otrzyma ramke z adresem MAC docelowym FF:FF:FF:FF:FF:FF?','./img/z74.jpg',0),(75,'Jakie dzialanie nastapi, jesli przelacznik otrzyma ramke i ma adres MAC zrodlowy w MAC stol?','./img/z75.jpg',0),(77,'Jakie dzialanie wystapi, jesli przelacznik otrzyma ramke i ma adres MAC zrodlowy w adresie MAC stol?','./img/z77.jpg',0),(78,'Jaka akcja wystapi, jesli host otrzyma ramke z adresem MAC docelowym, ktorego nie rozpoznaje?','./img/z78.jpg',0),(80,'Jaki typ kabla UTP jest uzywany do podlaczenia komputera PC do port przelacznika?','./img/z80.jpg',0);
